// 1. 從前面的三個節點抓取資料
const trips = $items("Get Trips").map(i => i.json);
const itineraries = $items("Get Itinerary").map(i => i.json);
const foods = $items("Get Foods").map(i => i.json);

// 2. 開始重組資料：只挑選 Status 是 active 的資料夾
const formattedTrips = trips.filter(t => t.Status === 'active').map(trip => {

    // --- 處理行程 (Itinerary) ---
    // 找出屬於這個 Trip_ID 的所有行程
    const tripItineraries = itineraries.filter(i => i.Trip_ID === trip.Trip_ID);

    // 按照 Day_Label (例如 Day 1, Day 2) 分組
    const daysMap = {};
    tripItineraries.forEach(item => {
        if (!daysMap[item.Day_Label]) {
            daysMap[item.Day_Label] = {
                id: `day_${item.Day_Label}_${trip.Trip_ID}`, 
                label: item.Day_Label,
                items: []
            };
        }

        // 塞入單筆行程細節
        daysMap[item.Day_Label].items.push({
            id: item.Item_ID,
            time: item.Time,
            title: item.Title,
            desc: item.Desc || '',
            url: item.URL || '',
            isHidden: item.Is_Hidden === 'TRUE' || item.Is_Hidden === true, // 處理布林值
            sortOrder: parseInt(item.Sort_Order) || 99
        });
    });

    // 將分組好的天數轉成陣列，並依照時間或 Sort_Order 排序
    const days = Object.values(daysMap);
    days.forEach(day => {
        day.items.sort((a, b) => a.sortOrder - b.sortOrder);
    });

    // --- 處理美食 (Foods) ---
    // 找出屬於這個 Trip_ID 的美食
    const tripFoods = foods.filter(f => f.Trip_ID === trip.Trip_ID).map(f => ({
        id: f.Food_ID,
        icon: f.Icon_Key,
        title: f.Title,
        desc: f.Desc || '',
        url: f.URL || ''
    }));

    // 3. 回傳最終組裝好的這個資料夾
    return {
        id: trip.Trip_ID,
        name: trip.Trip_Name,
        days: days,
        foods: tripFoods
    };
});

// 4. n8n 最終輸出的格式
return [{ json: { success: true, data: formattedTrips } }];

